import type { CashVoucherDto, PurchaseInvoiceDto } from '../../../../../services/kt/models';
import type { DatePageFilter } from '../../../../../services/kt/models';
import { ktService } from '../../../../../services/kt/ktService';
import { purchaseInvoiceTestIdPrefix } from '../../../../../components/kt/purchaseInvoiceTestId';

/** Map list DTO → shape expected by VoucherSearchSlideout (CashVoucherDto fields). */
export function purchaseInvoiceToSearchRow(d: PurchaseInvoiceDto): CashVoucherDto {
  return {
    id: d.id,
    code: d.code,
    voucherDate: d.invoiceDate,
    voucherType: d.voucherCode,
    receiptKind: '',
    customerName: d.supplierName,
    accountCode: d.creditAccountCode,
    amount: d.totalAmount,
    exchangeRate: 1,
    status: d.status,
    processingLevel: d.processingLevel ?? '',
    lines: [],
    createdAt: d.createdAt,
  };
}

export function getPurchaseInvoiceConfig(voucherCode: string, listPath: string, title: string) {
  const testIdPrefix = purchaseInvoiceTestIdPrefix(voucherCode);
  return {
    title,
    voucherCode,
    listPath,
    testIdPrefix,
    searchListScope: `${testIdPrefix}-search`,
    fetchList: async (filter?: DatePageFilter) => {
      const res = await ktService.getPurchaseInvoices({
        ...filter,
        voucherCode,
      });
      return {
        items: res.items.map(purchaseInvoiceToSearchRow),
        totalCount: res.totalCount,
      };
    },
    get: ktService.getPurchaseInvoice,
    getPostingStatus: ktService.getPurchaseInvoicePostingStatus,
    getPostedLedger: ktService.getPurchaseInvoicePostedLedger,
  };
}

export type PurchaseInvoiceConfig = ReturnType<typeof getPurchaseInvoiceConfig>;
